//		else begin
//			// Hack to silence DAC since it is left at 7 on sample playback
//			if (TempSound != 8'd0 && GrobdaDAC == 4'd7) begin
//				GrobdaDAC <= 4'd0;
//			end
//		end
//	end
//end

WSG_8CH wsg
(
    .CLK24M(CLK24M),
    .ADDR(SCPU_ADRS[5:0]),.DATA(SCPU_DO),.WE(SCPU_WE_WSG),
